What does this program print?

```cpp
#include <iostream>

void show(int a, int b = 10, int c = 20)
{
    std::cout << a << ' ' << b << ' ' << c << '\n';
}

int main()
{
    show(1);
    show(1, 2);
    show(1, 2, 3);
    return 0;
}
```

